using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that call an external API via HttpClient.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a resource from the JSONPlaceholder API by its numeric ID.")]
    public async Task<string> GetPost(
        [Description("The numeric post ID to retrieve (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var response = await httpClient.GetAsync($"/posts/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

/// <summary>
/// MCP prompt templates for summarization tasks.
/// </summary>
[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a single concise sentence.")]
    public static ChatMessage Summarize(
        [Description("The text content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into one concise sentence:\n\n{content}");
}

